    "sqlQuery": "SELECT\\n  SUM(`order_event`.`total_revenue`) AS `revenue_last_360_days`\\nFROM\\n  `order_event`\\nWHERE\\n  (\\n    `order_event`.`date` >= DATEADD (day, -360, CURRENT_DATE())\\n    AND `order_event`.`date` <= NOW ()\\n  )",
